features.snippet:
module Other(output zero); assign zero = 1'b0; endmodule
module Foo(input clock, input reset, output value);
  wire test; reg shared;
  Other other();
  always @(posedge clock) begin
    if (reset) shared <= other.zero;
    else shared <= shared;
  end
  assign test = shared;
  assign value = test;
endmodule
